revision.text:
/* {{sandbox other|| {{pp-template}} }} */
.navbar {
	display: inline;
	font-size: 75%;		/* 英語版では88% */
	font-weight: normal;
}

.navbar-collapse {
	float: left;
	text-align: left;
}

.navbar-boxtext {
	word-spacing: 0;
}

.navbar ul {
	display: inline-block;
	white-space: nowrap;
	line-height: inherit;
}

.navbar-brackets::before {
	margin-right: -0.125em;
	content: '[ ';
}

.navbar-brackets::after {
	margin-left: -0.125em;
	content: ' ]';
}

.navbar li {
	word-spacing: -0.125em;
}

.navbar a > span,
.navbar a > abbr {
	text-decoration: inherit;
}

.navbar-mini abbr {
	font-variant: small-caps;
	border-bottom: none;
	text-decoration: none;
	cursor: inherit;
}

.navbar-ct-full {
	font-size: 110%;		/* 英語版では114% */
	margin: 0 7em;
}

.navbar-ct-mini {
	font-size: 110%;		/* 英語版では114% */
	margin: 0 4em;
}

/* not the usual @media screen, we simply remove navbar in @media print */
html.skin-theme-clientpref-night .navbar li a abbr {
	color: var(--color-base) !important;
}

@media (prefers-color-scheme: dark) {
	html.skin-theme-clientpref-os .navbar li a abbr {
		color: var(--color-base) !important;
	}
}

@media print {
	.navbar {
		display: none !important;
	}
}

/* 以下は英語版では除去済みだが、日本語版ではまだ残しておく */
/* Navbar styling when nested in infobox and navbox
Should consider having a separate TemplateStyles for those specific places
using an infobox/navbox and a navbar, or possibly override from using template */
.infobox .navbar {
	font-size: 80%;		/* 英語版では100% */
}

.navbox .navbar {
	display: block;
	font-size: 80%;		/* 英語版では100% */
}

.navbox-title .navbar {
	/* @noflip */
	float: left;
	/* @noflip */
	text-align: left;
	/* @noflip */
	margin-right: 0.5em;
}
/* {{sandbox other|| [[Category:テンプレートスタイル]] }} */

